# Dream Sequence Manager Script

def main():
    # List of dream sequences stored in plain text
    dream_sequences = [
        'Flying over mountains',
        'Walking through a forest'
    ]

    # Printing dream sequences for visualization
    for dream in dream_sequences:
        print(dream)

    # Store dream sequences in a backup file
    with open('backup_dreams.txt', 'w') as backup:
        for dream in dream_sequences:
            backup.write(dream + '\n')

if __name__ == '__main__':
    main()

